import axios from 'axios'
import type { ApiResponse } from '@/types/common'

const ACCESS_TOKEN_KEY = 'imv_access_token'
const REFRESH_TOKEN_KEY = 'imv_refresh_token'

export const tokenStorage = {
  getAccess: () => localStorage.getItem(ACCESS_TOKEN_KEY),
  getRefresh: () => localStorage.getItem(REFRESH_TOKEN_KEY),
  set: (access: string, refresh: string) => {
    localStorage.setItem(ACCESS_TOKEN_KEY, access)
    localStorage.setItem(REFRESH_TOKEN_KEY, refresh)
  },
  clear: () => {
    localStorage.removeItem(ACCESS_TOKEN_KEY)
    localStorage.removeItem(REFRESH_TOKEN_KEY)
  },
}

const client = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL,
  headers: { 'Content-Type': 'application/json' },
})

// Attach token to every request
client.interceptors.request.use((config) => {
  const token = tokenStorage.getAccess()
  if (token) config.headers.Authorization = `Bearer ${token}`
  return config
})

let isRefreshing = false
let refreshQueue: Array<(token: string) => void> = []

// On 401 → try refresh → retry original request
client.interceptors.response.use(
  (response) => response,
  async (error) => {
    const original = error.config

    if (error.response?.status !== 401 || original._retry) {
      return Promise.reject(error)
    }

    const refreshToken = tokenStorage.getRefresh()
    if (!refreshToken) {
      tokenStorage.clear()
      // Don't hard-redirect if already on /login or PKCE SSO flow is in progress
      const onLoginPage = window.location.pathname === '/login' || window.location.pathname.startsWith('/auth/')
      const pkceInProgress = !!localStorage.getItem('pkce_code_verifier')
      if (!onLoginPage && !pkceInProgress) {
        window.location.href = '/login'
      }
      return Promise.reject(error)
    }

    if (isRefreshing) {
      return new Promise((resolve) => {
        refreshQueue.push((newToken) => {
          original.headers.Authorization = `Bearer ${newToken}`
          resolve(client(original))
        })
      })
    }

    original._retry = true
    isRefreshing = true

    try {
      const res = await axios.post<ApiResponse<{ accessToken: string; refreshToken: string }>>(
        `${import.meta.env.VITE_API_BASE_URL}/auth/refresh`,
        { refreshToken },
      )
      const { accessToken, refreshToken: newRefresh } = res.data.data!
      tokenStorage.set(accessToken, newRefresh)
      refreshQueue.forEach((cb) => cb(accessToken))
      refreshQueue = []
      original.headers.Authorization = `Bearer ${accessToken}`
      return client(original)
    } catch {
      tokenStorage.clear()
      window.location.href = '/login'
      return Promise.reject(error)
    } finally {
      isRefreshing = false
    }
  },
)

export default client
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { authApi } from '@/api/auth'
import { tokenStorage } from '@/api/client'
import type { UserDto, Role } from '@/types/auth'

export const useAuthStore = defineStore('auth', () => {
  const user = ref<UserDto | null>(null)
  const accessToken = ref<string | null>(tokenStorage.getAccess())
  const refreshToken = ref<string | null>(tokenStorage.getRefresh())

  const isLoggedIn = computed(() => !!accessToken.value && !!user.value)
  const role = computed(() => user.value?.role ?? null)

  function hasRole(roles: string[]): boolean {
    return !!role.value && roles.includes(role.value)
  }

  function setTokens(access: string, refresh: string) {
    accessToken.value = access
    refreshToken.value = refresh
    tokenStorage.set(access, refresh)
  }

  function clearAuth() {
    user.value = null
    accessToken.value = null
    refreshToken.value = null
    tokenStorage.clear()
  }

  async function devLogin(params: { role: Role; pinfl?: string; fullName?: string; departmentId?: string; departmentName?: string }) {
    const res = await authApi.devLogin(params)
    const data = res.data.data!
    setTokens(data.accessToken, data.refreshToken)
    user.value = data.user
  }

  async function ssoLogin(code: string, codeVerifier: string, redirectUri: string) {
    const res = await authApi.token({
      grantType: 'authorization_code',
      code,
      codeVerifier,
      redirectUri,
    })
    const data = res.data.data!
    setTokens(data.accessToken, data.refreshToken)
    user.value = data.user
  }

  async function fetchCurrentUser() {
    const res = await authApi.me()
    user.value = res.data.data!
  }

  async function logout() {
    if (refreshToken.value) {
      // SECURITY: Token stored in localStorage. Ensure strict CSP headers are set on
      // the server (SecurityConfig.kt) to mitigate XSS risk. For higher-security
      // government deployments, consider migrating to httpOnly cookies.
      await authApi.logout(refreshToken.value).catch((err) => {
        console.warn('Token revocation failed — server-side token may still be active:', err)
      })
    }
    clearAuth()
  }

  return {
    user,
    accessToken,
    refreshToken,
    isLoggedIn,
    role,
    hasRole,
    setTokens,
    clearAuth,
    devLogin,
    ssoLogin,
    fetchCurrentUser,
    logout,
  }
})

