        }
    }

    @Transactional(readOnly = true)
    fun listOwn(principal: UserPrincipal, status: RequestStatus?, pageable: Pageable): Page<ApprovalRequestDto> {
        val page = if (status != null)
            requestRepository.findByRequestedByAndStatus(principal.id, status, pageable)
        else
            requestRepository.findByRequestedBy(principal.id, pageable)
        val sentPagesMap = batchLoadSentPages(page.content.map { it.id })
        return page.map { it.toDto(sentPageIds = sentPagesMap[it.id] ?: emptyList()) }
    }

    @Transactional(readOnly = true)
    fun listAll(status: RequestStatus?, pageable: Pageable): Page<ApprovalRequestDto> {
        val page = if (status != null)
            requestRepository.findByStatus(status, pageable)
        else
            requestRepository.findAll(pageable)
        val nameMap = batchLoadNames(page.content.map { it.requestedBy })
        val approverMap = batchLoadNames(page.content.mapNotNull { it.approverId })
        val sentPagesMap = batchLoadSentPages(page.content.map { it.id })
        return page.map { req ->
            req.toDto(
                requestedByName = nameMap[req.requestedBy],
                approverName = req.approverId?.let { approverMap[it] },
                sentPageIds = sentPagesMap[req.id] ?: emptyList(),
            )
        }
    }

    @Transactional(readOnly = true)
    fun inbox(status: RequestStatus?, pageable: Pageable): Page<ApprovalRequestDto> {
        val page = if (status != null)
            requestRepository.findByStatus(status, pageable)
        else
            requestRepository.findAll(pageable)
        val requesterIds = page.content.map { it.requestedBy }.distinct()
        val users = userRepository.findAllWithDepartmentByIdIn(requesterIds)
        val nameMap = users.associate { it.id to it.fullName }
        val deptMap = users.associate { it.id to it.department?.name }
        val sentPagesMap = batchLoadSentPages(page.content.map { it.id })
        return page.map { req ->
            req.toDto(
                requestedByName = nameMap[req.requestedBy],
                requestedByDepartment = deptMap[req.requestedBy],
                sentPageIds = sentPagesMap[req.id] ?: emptyList(),
            )
        }
    }

    @Transactional(readOnly = true)
    fun getById(id: UUID, principal: UserPrincipal): ApprovalRequestDto {
        val request = requestRepository.findByIdOrNull(id) ?: throw BusinessException(ErrorCode.REQUEST_NOT_FOUND)
        if (principal.role.name == "USER" && request.requestedBy != principal.id) {
            throw BusinessException(ErrorCode.INSUFFICIENT_PERMISSIONS)
        }
        val requester = userRepository.findWithDepartmentById(request.requestedBy).orElse(null)
        val approverName = request.approverId?.let { userRepository.findById(it).map { u -> u.fullName }.orElse(null) }
        val sentPageIds = sentPageRepository.findByRequestId(id).map { it.documentPageId }
        return request.toDto(
            requestedByName = requester?.fullName,
            requestedByDepartment = requester?.department?.name,
            approverName = approverName,
            sentPageIds = sentPageIds,
        )
    }

    private fun batchLoadNames(ids: List<UUID>): Map<UUID, String> =
        userRepository.findAllById(ids.distinct()).associate { it.id to it.fullName }

    private fun batchLoadSentPages(requestIds: List<UUID>): Map<UUID, List<UUID>> =
        sentPageRepository.findByRequestIdIn(requestIds)
            .groupBy({ it.requestId }, { it.documentPageId })
}
package uz.gov.imvarxiv.request.application

import org.slf4j.LoggerFactory
import org.springframework.data.repository.findByIdOrNull
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import uz.gov.imvarxiv.document.infrastructure.DocumentPageRepository
import uz.gov.imvarxiv.document.infrastructure.DocumentRepository
