import uz.gov.imvarxiv.request.infrastructure.ApprovalRequestRepository
import uz.gov.imvarxiv.request.infrastructure.RequestSentPageRepository
import uz.gov.imvarxiv.shared.exception.BusinessException
import uz.gov.imvarxiv.shared.exception.ErrorCode
import uz.gov.imvarxiv.shared.security.UserPrincipal
import java.time.Instant
import java.util.UUID

@Service
class ApprovalWorkflowService(
    private val requestRepository: ApprovalRequestRepository,
    private val sentPageRepository: RequestSentPageRepository,
    private val documentRepository: DocumentRepository,
    private val documentPageRepository: DocumentPageRepository,
) {
    private val log = LoggerFactory.getLogger(this::class.java)

    @Transactional
    fun approve(id: UUID, principal: UserPrincipal, comment: String?): ApprovalRequestDto {
        val request = requestRepository.findByIdOrNull(id) ?: throw BusinessException(ErrorCode.REQUEST_NOT_FOUND)
        if (request.status != RequestStatus.PENDING) throw BusinessException(ErrorCode.REQUEST_NOT_APPROVABLE)
        request.status = RequestStatus.APPROVED
        request.approverId = principal.id
        request.approverComment = comment
        request.approvedAt = Instant.now()
        log.info("Request approved: id={} by={}", id, principal.id)
        return requestRepository.save(request).toDto()
    }

    @Transactional
    fun reject(id: UUID, principal: UserPrincipal, comment: String): ApprovalRequestDto {
        val request = requestRepository.findByIdOrNull(id) ?: throw BusinessException(ErrorCode.REQUEST_NOT_FOUND)
        if (request.status != RequestStatus.PENDING) throw BusinessException(ErrorCode.REQUEST_NOT_APPROVABLE)
        request.status = RequestStatus.REJECTED
        request.approverId = principal.id
        request.approverComment = comment
        request.approvedAt = Instant.now()
        log.info("Request rejected: id={} by={}", id, principal.id)
        return requestRepository.save(request).toDto()
    }

    @Transactional
    fun send(id: UUID, principal: UserPrincipal, dto: SendRequestDto): ApprovalRequestDto {
        val request = requestRepository.findByIdOrNull(id) ?: throw BusinessException(ErrorCode.REQUEST_NOT_FOUND)
        if (request.status != RequestStatus.APPROVED) throw BusinessException(ErrorCode.REQUEST_NOT_APPROVED)

        documentRepository.findByIdOrNull(dto.documentId) ?: throw BusinessException(ErrorCode.DOCUMENT_NOT_FOUND)
        if (dto.pageIds.isEmpty()) throw BusinessException(ErrorCode.VALIDATION_ERROR, mapOf("pageIds" to "Kamida bitta sahifa tanlang"))

        // Verify all page IDs belong to the document
        val pages = documentPageRepository.findAllById(dto.pageIds)
        if (pages.any { it.documentId != dto.documentId }) {
            throw BusinessException(ErrorCode.VALIDATION_ERROR, mapOf("pageIds" to "Sahifalar hujjatga tegishli emas"))
        }

        sentPageRepository.deleteByRequestId(id)
        dto.pageIds.forEach { pageId ->
            sentPageRepository.save(RequestSentPage(requestId = id, documentPageId = pageId))
        }

        request.documentId = dto.documentId
        request.moderatorId = principal.id
        request.sentAt = Instant.now()
        request.status = RequestStatus.SENT
        log.info("Request sent: id={} by={} pages={}", id, principal.id, dto.pageIds.size)
        val sentPageIds = sentPageRepository.findByRequestId(id).map { it.documentPageId }
        return requestRepository.save(request).toDto(sentPageIds = sentPageIds)
    }
}

