@Service
class DocumentService(
    private val documentRepository: DocumentRepository,
    private val documentPageRepository: DocumentPageRepository,
    private val departmentRepository: DepartmentRepository,
    private val storageService: StorageService,
    private val pdfProcessingService: PdfProcessingService,
) {
    private val log = LoggerFactory.getLogger(this::class.java)

    /** Returns the MinIO folder prefix for a document, e.g. "documents/Xizmatchilar_shaxsiy_ishlari-<uuid>" */
    private fun docFolder(doc: Document): String {
        val slug = doc.documentName
            .take(50)
            .trim()
            .replace(Regex("[/\\\\:*?\"<>|\\x00-\\x1F]"), "")
            .replace(Regex("\\s+"), "_")
            .trimEnd('_')
            .ifEmpty { "doc" }
