package uz.gov.imvarxiv.document.application

import org.apache.pdfbox.Loader
import org.apache.pdfbox.rendering.ImageType
import org.apache.pdfbox.rendering.PDFRenderer
import org.slf4j.LoggerFactory
import org.springframework.data.repository.findByIdOrNull
import org.springframework.scheduling.annotation.Async
import org.springframework.stereotype.Service
import uz.gov.imvarxiv.document.domain.DocumentPage
import uz.gov.imvarxiv.document.domain.UploadStatus
import uz.gov.imvarxiv.document.infrastructure.DocumentPageRepository
import uz.gov.imvarxiv.document.infrastructure.DocumentRepository
import uz.gov.imvarxiv.shared.storage.StorageService
import java.io.ByteArrayInputStream
import java.io.ByteArrayOutputStream
import java.nio.file.Files
import java.nio.file.StandardCopyOption
import java.util.UUID
import javax.imageio.ImageIO

@Service
class PdfProcessingService(
    private val documentRepository: DocumentRepository,
    private val documentPageRepository: DocumentPageRepository,
    private val storageService: StorageService,
) {
    private val log = LoggerFactory.getLogger(this::class.java)

    @Async("pdfProcessingExecutor")
    fun processAsync(documentId: UUID, pdfStorageKey: String, folderPrefix: String) {
        log.info("PDF processing started: docId={} key={}", documentId, pdfStorageKey)

        // Download PDF to a temp file — PDFBox needs random access for large PDFs
        val tempFile = Files.createTempFile("pdf-proc-$documentId-", ".pdf")
        try {
            storageService.download(pdfStorageKey).use { stream ->
                Files.copy(stream, tempFile, StandardCopyOption.REPLACE_EXISTING)
            }

            Loader.loadPDF(tempFile.toFile()).use { pdf ->
                val totalPages = pdf.numberOfPages
                log.info("PDF loaded: docId={} pages={}", documentId, totalPages)

                // Save total page count
                documentRepository.findByIdOrNull(documentId)?.let { doc ->
                    doc.pdfPageCount = totalPages
                    documentRepository.save(doc)
                }

                // Delete existing pages — clean slate before re-processing
                documentPageRepository.deleteAllByDocumentId(documentId)

                val renderer = PDFRenderer(pdf)
                for (pageIndex in 0 until totalPages) {
                    val pageNum = pageIndex + 1
                    val storageKey = "$folderPrefix/pages/$pageNum.jpg"

                    // Render page to JPEG — 150 DPI balances quality and file size
                    val image = renderer.renderImageWithDPI(pageIndex, 150f, ImageType.RGB)
                    val jpegBytes = ByteArrayOutputStream().also { out ->
                        ImageIO.write(image, "JPEG", out)
                    }.toByteArray()

                    storageService.upload(ByteArrayInputStream(jpegBytes), storageKey, "image/jpeg", jpegBytes.size.toLong())
                    documentPageRepository.save(
                        DocumentPage(documentId = documentId, pageNumber = pageNum, storageKey = storageKey)
                    )

                    log.info("PDF page done: docId={} page={}/{}", documentId, pageNum, totalPages)
                }

                markStatus(documentId, UploadStatus.DONE)
                log.info("PDF processing complete: docId={} totalPages={}", documentId, totalPages)
            }
        } catch (ex: Exception) {
            log.error("PDF processing failed: docId={}", documentId, ex)
            markStatus(documentId, UploadStatus.FAILED)
        } finally {
            Files.deleteIfExists(tempFile)
        }
    }

    private fun markStatus(documentId: UUID, status: UploadStatus) {
        documentRepository.findByIdOrNull(documentId)?.let { doc ->
            doc.uploadStatus = status
            documentRepository.save(doc)
        }
    }
}

