import uz.gov.imvarxiv.shared.security.UserDetailsServiceImpl

@Configuration
@EnableWebSecurity
@EnableMethodSecurity(prePostEnabled = true)
class SecurityConfig(
    private val jwtTokenProvider: JwtTokenProvider,
    private val userDetailsService: UserDetailsServiceImpl,
    private val objectMapper: ObjectMapper,
    private val environment: Environment,
    @Value("\${app.cors.allowed-origins}") private val allowedOrigins: String,
) {

    @Bean
    fun filterChain(http: HttpSecurity): SecurityFilterChain {
        val isProd = environment.activeProfiles.contains("prod")

        http
            .csrf { it.disable() }
            .cors { it.configurationSource(corsConfigurationSource()) }
            .sessionManagement { it.sessionCreationPolicy(SessionCreationPolicy.STATELESS) }
            .headers { h ->
                h.frameOptions { it.deny() }
                h.contentTypeOptions { }
                h.xssProtection { }
                if (isProd) {
                    h.httpStrictTransportSecurity { hsts ->
                        hsts.includeSubDomains(true)
                        hsts.maxAgeInSeconds(31536000)
                    }
                }
                h.contentSecurityPolicy { csp ->
                    csp.policyDirectives("default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data:")
                }
            }
            .authorizeHttpRequests { auth ->
                auth
                    .requestMatchers(
                        "/auth/login-url",
                        "/auth/token",
                        "/auth/refresh",
                        "/auth/dev/**",
                        "/actuator/**",
                        "/v3/api-docs/**",
                        "/swagger-ui/**",
                        "/swagger-ui.html",
                    ).permitAll()
                    .anyRequest().authenticated()
            }
            .exceptionHandling { ex ->
                ex.authenticationEntryPoint(authenticationEntryPoint())
                ex.accessDeniedHandler(accessDeniedHandler())
            }
            .addFilterBefore(
                JwtAuthenticationFilter(jwtTokenProvider, userDetailsService),
                UsernamePasswordAuthenticationFilter::class.java,
            )

        return http.build()
    }

    @Bean
    fun corsConfigurationSource(): CorsConfigurationSource {
        val isProd = environment.activeProfiles.contains("prod")
        val parsedOrigins = this@SecurityConfig.allowedOrigins.split(",").map { it.trim() }
        if (isProd) {
            require(parsedOrigins.all { it.startsWith("https://") }) {
                "All CORS allowed origins must use HTTPS in prod profile. Got: $parsedOrigins"
            }
        }
        val config = CorsConfiguration().apply {
            allowedOrigins = parsedOrigins
            allowedMethods = listOf("GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS")
            allowedHeaders = listOf("Authorization", "Content-Type", "X-Request-Id")
            allowCredentials = true
            maxAge = 3600L
        }
        return UrlBasedCorsConfigurationSource().apply {
            registerCorsConfiguration("/**", config)
        }
    }

    private fun authenticationEntryPoint() = AuthenticationEntryPoint { _, response, _ ->
        writeErrorResponse(response, HttpStatus.UNAUTHORIZED, ErrorCode.INVALID_TOKEN)
    }

    private fun accessDeniedHandler() = AccessDeniedHandler { _, response, _ ->
        writeErrorResponse(response, HttpStatus.FORBIDDEN, ErrorCode.INSUFFICIENT_PERMISSIONS)
    }

    private fun writeErrorResponse(
        response: HttpServletResponse,
        status: HttpStatus,
        errorCode: ErrorCode,
    ) {
        response.status = status.value()
        response.contentType = MediaType.APPLICATION_JSON_VALUE
        response.characterEncoding = "UTF-8"
        objectMapper.writeValue(response.writer, ApiResponse.error<Nothing>(errorCode))
    }
}

