            ?: run {
                log.warn("SSO login rejected: unregistered pinfl={}", claims.pinfl)
                throw BusinessException(ErrorCode.SSO_USER_NOT_ALLOWED)
            }
        // SSO dan kelgan ism/email ni yangilash
        user.fullName = claims.fullName
        if (claims.email != null) user.email = claims.email
        return userRepository.save(user)
    }

    private fun revokeRefreshToken(userId: UUID, rawToken: String) {
        val tokenHash = sha256(rawToken)
        val stored = refreshTokenRepository.findByTokenHash(tokenHash) ?: return
        if (stored.userId != userId) return
        stored.revoked = true
        stored.revokedAt = Instant.now()
        refreshTokenRepository.save(stored)
    }

    private fun saveRefreshToken(
        userId: UUID,
        rawToken: String,
        expiresAt: Instant,
        clientIp: String?,
        userAgent: String?,
    ) {
        refreshTokenRepository.save(
            RefreshToken(
                userId = userId,
                tokenHash = sha256(rawToken),
                expiresAt = expiresAt,
                clientIp = clientIp,
                userAgent = userAgent,
            ),
        )
    }

    private fun sha256(input: String): String {
        val digest = MessageDigest.getInstance("SHA-256")
        return digest.digest(input.toByteArray()).joinToString("") { "%02x".format(it) }
    }
