enum class ErrorCode(val httpStatus: HttpStatus) {
    // User
    USER_NOT_FOUND(HttpStatus.NOT_FOUND),
    USER_NOT_ACTIVE(HttpStatus.FORBIDDEN),
    SSO_USER_NOT_ALLOWED(HttpStatus.FORBIDDEN),

    // Auth / Token
    INSUFFICIENT_PERMISSIONS(HttpStatus.FORBIDDEN),
    INVALID_TOKEN(HttpStatus.UNAUTHORIZED),
    TOKEN_EXPIRED(HttpStatus.UNAUTHORIZED),
    TOKEN_REVOKED(HttpStatus.UNAUTHORIZED),

    // Document
    DOCUMENT_NOT_FOUND(HttpStatus.NOT_FOUND),
    PDF_ALREADY_PROCESSING(HttpStatus.CONFLICT),
    PDF_PROCESSING_FAILED(HttpStatus.INTERNAL_SERVER_ERROR),
    INVALID_PDF(HttpStatus.BAD_REQUEST),

    // Page upload
    PAGE_NOT_FOUND(HttpStatus.NOT_FOUND),
    INVALID_FILE_TYPE(HttpStatus.BAD_REQUEST),
    FILE_TOO_LARGE(HttpStatus.BAD_REQUEST),

    // Request
    REQUEST_NOT_FOUND(HttpStatus.NOT_FOUND),
    REQUEST_NOT_APPROVABLE(HttpStatus.BAD_REQUEST),
    REQUEST_NOT_APPROVED(HttpStatus.BAD_REQUEST),

    // Fond
    FOND_NOT_FOUND(HttpStatus.NOT_FOUND),

    // Template
    TEMPLATE_NOT_FOUND(HttpStatus.NOT_FOUND),

    // Department
    DEPARTMENT_NOT_FOUND(HttpStatus.NOT_FOUND),

    // Infrastructure
    STORAGE_UNAVAILABLE(HttpStatus.SERVICE_UNAVAILABLE),
    STORAGE_NOT_FOUND(HttpStatus.NOT_FOUND),
    SSO_UNAVAILABLE(HttpStatus.SERVICE_UNAVAILABLE),
    DATABASE_ERROR(HttpStatus.INTERNAL_SERVER_ERROR),

    // Generic
    VALIDATION_ERROR(HttpStatus.BAD_REQUEST),
    INTERNAL_ERROR(HttpStatus.INTERNAL_SERVER_ERROR),
}
