import org.springframework.web.bind.annotation.RestControllerAdvice
import org.springframework.web.servlet.NoHandlerFoundException
import uz.gov.imvarxiv.shared.logging.MdcKeys
import uz.gov.imvarxiv.shared.response.ApiResponse
import uz.gov.imvarxiv.shared.response.ErrorDetail

@RestControllerAdvice
class GlobalExceptionHandler {

    private val log = LoggerFactory.getLogger(this::class.java)

    @ExceptionHandler(BusinessException::class)
    fun handleBusinessException(ex: BusinessException): ResponseEntity<ApiResponse<Nothing>> {
        log.warn("Business exception: {} | details={}", ex.errorCode, ex.details)
        val response = if (ex.details != null) {
            ApiResponse.error<Nothing>(ex.errorCode, ex.details)
        } else {
            ApiResponse.error(ex.errorCode)
        }
        return ResponseEntity.status(ex.errorCode.httpStatus).body(response)
    }

    @ExceptionHandler(MethodArgumentNotValidException::class)
    fun handleValidation(ex: MethodArgumentNotValidException): ResponseEntity<ApiResponse<Nothing>> {
        val fieldErrors = ex.bindingResult.fieldErrors.associate { it.field to (it.defaultMessage ?: "invalid") }
        log.warn("Validation error: {}", fieldErrors)
        return ResponseEntity.badRequest().body(
            ApiResponse.error(ErrorCode.VALIDATION_ERROR, fieldErrors)
        )
    }

    @ExceptionHandler(AccessDeniedException::class)
    fun handleAccessDenied(ex: AccessDeniedException): ResponseEntity<ApiResponse<Nothing>> {
        log.warn("Access denied: {}", ex.message)
        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(
            ApiResponse.error(ErrorCode.INSUFFICIENT_PERMISSIONS)
        )
    }

    @ExceptionHandler(AuthenticationException::class)
    fun handleAuthentication(ex: AuthenticationException): ResponseEntity<ApiResponse<Nothing>> {
        log.warn("Authentication failed: {}", ex.message)
        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(
            ApiResponse.error(ErrorCode.INVALID_TOKEN)
        )
    }

    @ExceptionHandler(NoHandlerFoundException::class)
    fun handleNoHandler(ex: NoHandlerFoundException): ResponseEntity<ApiResponse<Nothing>> {
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(
            ApiResponse.error<Nothing>(ErrorCode.INTERNAL_ERROR).let {
                ApiResponse(
                    success = false,
                    error = ErrorDetail(
                        code = "NOT_FOUND",
                        message = "Path not found: ${ex.requestURL}",
                    ),
                )
            }
        )
    }

    @ExceptionHandler(HttpRequestMethodNotSupportedException::class)
    fun handleMethodNotSupported(ex: HttpRequestMethodNotSupportedException): ResponseEntity<ApiResponse<Nothing>> {
        return ResponseEntity.status(HttpStatus.METHOD_NOT_ALLOWED).body(
            ApiResponse(
                success = false,
                error = ErrorDetail(
                    code = "METHOD_NOT_ALLOWED",
                    message = "Method ${ex.method} not allowed",
                ),
            )
        )
    }

    @ExceptionHandler(Exception::class)
    fun handleGeneral(ex: Exception): ResponseEntity<ApiResponse<Nothing>> {
        val requestId = MDC.get(MdcKeys.REQUEST_ID)
        log.error("Unhandled exception [requestId={}]", requestId, ex)
        return ResponseEntity.internalServerError().body(
            ApiResponse.error(ErrorCode.INTERNAL_ERROR)
        )
    }
}

