3. Qaytgan loginUrl ga foydalanuvchini yo'naltiring
4. SSO login qilgach redirectUri?code=XXX ga qaytadi
5. Shu code + codeVerifier bilan POST /auth/token ga murojaat qiling

pkce-gen bash skriptidan foydalaning: /usr/local/bin/pkce-gen""",
    )
    fun loginUrl(
        @RequestParam @Schema(example = "E9Melhoa2OwvFrEMTJguCHaoeK1t8URWbuGJSstw-cM") codeChallenge: String,
        @RequestParam @Schema(example = "https://arxiv.yatm.uz/login") redirectUri: String,
    ): ResponseEntity<ApiResponse<Map<String, String>>> {
        val url = authService.getLoginUrl(codeChallenge, redirectUri)
        return ResponseEntity.ok(ApiResponse.success(mapOf("loginUrl" to url)))
    }

    @PostMapping("/token")
    @Operation(
        summary = "2-qadam: SSO callback code ni access token ga almashtirish",
        description = "SSO redirect dan kelgan code + original codeVerifier + bir xil redirectUri yuboriladi. Muvaffaqiyatli bo'lsa accessToken + refreshToken qaytadi.",
    )
    fun token(
        @Valid @RequestBody body: TokenRequest,
        request: HttpServletRequest, 
        ): ResponseEntity<ApiResponse<AuthResponse>> {

        val clientIp  = getClientIp(request)
        val userAgent = request.getHeader("User-Agent")
        val response = authService.ssoLogin(
            body.code, 
            body.codeVerifier, 
            body.redirectUri, 
            clientIp, 
            userAgent
        )

        return ResponseEntity.ok(ApiResponse.success(response))
    }

    @PostMapping("/refresh")
    @Operation(summary = "Access token yangilash (backend refresh token bilan)")
    fun refresh(
        @Valid @RequestBody body: RefreshRequest,
        request: HttpServletRequest,
    ): ResponseEntity<ApiResponse<AuthResponse>> {
        val clientIp  = getClientIp(request)
        val userAgent = request.getHeader("User-Agent")
        val response  = authService.refreshToken(body.refreshToken, clientIp, userAgent)
        return ResponseEntity.ok(ApiResponse.success(response))
    }

    @PostMapping("/logout")
    @Operation(summary = "Tizimdan chiqish — refresh token bekor qilish")
    fun logout(
        @Valid @RequestBody body: LogoutRequest,
        @CurrentUser principal: UserPrincipal,
    ): ResponseEntity<ApiResponse<Nothing>> {
        authService.logout(body.refreshToken, principal.id)
