import java.util.UUID

@RestController
@RequestMapping("/auth/dev")
@Profile("dev", "stage")
@Tag(name = "Dev Auth", description = "Development-only manual login (disabled in production)")
class DevAuthController(
    private val userRepository: UserRepository,
    private val departmentRepository: DepartmentRepository,
    private val refreshTokenRepository: RefreshTokenRepository,
    private val jwtTokenProvider: JwtTokenProvider,
    @Value("\${app.jwt.access-token-expiration}") private val accessExpiration: Long,
    @Value("\${app.jwt.refresh-token-expiration}") private val refreshExpiration: Long,
) {
    private val log = LoggerFactory.getLogger(DevAuthController::class.java)

    @PostMapping("/login")
    @Transactional
    @Operation(
        summary = "Dev/Stage login — SSO siz token olish",
        description = """Faqat dev va stage muhitda mavjud. Production da 404 qaytaradi.
Har safar role request dagi qiymatga o'rnatiladi — bir xil pinfl bilan turli role sinab ko'rish mumkin.
departmentId yoki departmentName dan biri yuborilsa department o'rnatiladi, ikkalasi ham yuborilmasa department null qoladi.""",
    )
    fun login(
        @Valid @RequestBody request: DevLoginRequest,
    ): ResponseEntity<ApiResponse<AuthResponse>> {
        val devPinfl = request.pinfl ?: "dev-${request.role.name}"

        val department = when {
            request.departmentId != null -> departmentRepository.findById(request.departmentId).orElse(null)
            request.departmentName != null -> departmentRepository.findByName(request.departmentName).orElse(null)
            else -> null
        }

        val user = userRepository.findByPinfl(devPinfl).orElseGet {
            userRepository.save(
                User(
                    pinfl = devPinfl,
                    fullName = request.fullName ?: "Dev ${request.role.name}",
                    email = "dev-${request.role.name.lowercase()}@imvarxiv.dev",
                    role = request.role,
                    department = department,
                ),
            ).also { log.info("Dev user created: pinfl={} role={}", devPinfl, request.role) }
        }.also { existing ->
            existing.role = request.role
            if (request.fullName != null) existing.fullName = request.fullName
            if (request.departmentId != null || request.departmentName != null) existing.department = department
        }

        val principal = UserPrincipal.from(user)
        val tokenPair = jwtTokenProvider.generateTokenPair(principal)

        // DEV ONLY: IP and User-Agent hardcoded — audit trail not meaningful in dev profile
        refreshTokenRepository.save(
            RefreshToken(
                userId = user.id,
                tokenHash = sha256(tokenPair.refreshToken),
                expiresAt = tokenPair.refreshTokenExpiresAt,
                clientIp = "dev",
                userAgent = "DevAuthController",
            ),
        )

        log.info("Dev login: userId={} role={} dept={}", user.id, user.role, department?.name)

        return ResponseEntity.ok(
            ApiResponse.success(
                AuthResponse(
                    accessToken = tokenPair.accessToken,
                    refreshToken = tokenPair.refreshToken,
                    expiresIn = accessExpiration,
                    user = user.toDto(),
                ),
            ),
        )
    }

    private fun sha256(input: String): String {
        val digest = MessageDigest.getInstance("SHA-256")
        return digest.digest(input.toByteArray()).joinToString("") { "%02x".format(it) }
    }
}

data class DevLoginRequest(
