import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import uz.gov.imvarxiv.request.application.dto.CreateTemplateDto
import uz.gov.imvarxiv.request.application.dto.RequestTemplateDto
import uz.gov.imvarxiv.request.application.dto.UpdateTemplateDto
import uz.gov.imvarxiv.request.application.dto.toDto
