import org.slf4j.LoggerFactory
import org.springframework.data.domain.Page
import org.springframework.data.domain.Pageable
import org.springframework.data.repository.findByIdOrNull
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import uz.gov.imvarxiv.shared.exception.BusinessException
import uz.gov.imvarxiv.shared.exception.ErrorCode
import uz.gov.imvarxiv.user.application.dto.CreateDepartmentDto
import uz.gov.imvarxiv.user.application.dto.CreateUserDto
