package uz.gov.imvarxiv.user.application

import org.slf4j.LoggerFactory
import org.springframework.data.domain.Page
import org.springframework.data.domain.Pageable
import org.springframework.data.repository.findByIdOrNull
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import uz.gov.imvarxiv.shared.exception.BusinessException
import uz.gov.imvarxiv.shared.exception.ErrorCode
import uz.gov.imvarxiv.user.application.dto.CreateDepartmentDto
import uz.gov.imvarxiv.user.application.dto.CreateUserDto
import uz.gov.imvarxiv.user.application.dto.DepartmentDto
import uz.gov.imvarxiv.user.application.dto.UpdateDepartmentDto
import uz.gov.imvarxiv.user.application.dto.UpdateUserDto
import uz.gov.imvarxiv.user.application.dto.UserDto
import uz.gov.imvarxiv.user.application.dto.toDepartmentDto
import uz.gov.imvarxiv.user.application.dto.toDto
import uz.gov.imvarxiv.user.domain.Department
import uz.gov.imvarxiv.user.domain.Role
import uz.gov.imvarxiv.user.domain.User
import uz.gov.imvarxiv.user.infrastructure.DepartmentRepository
import uz.gov.imvarxiv.user.infrastructure.UserRepository
import java.util.UUID

@Service
class UserService(
    private val userRepository: UserRepository,
    private val departmentRepository: DepartmentRepository,
) {
    private val log = LoggerFactory.getLogger(this::class.java)

    // ─── Users ───────────────────────────────────────────────────────────────

    @Transactional(readOnly = true)
    fun listUsers(role: Role?, isActive: Boolean?, pageable: Pageable): Page<UserDto> {
        return when {
            role != null && isActive != null -> userRepository.findByRoleAndIsActive(role, isActive, pageable)
            role != null -> userRepository.findByRole(role, pageable)
            isActive != null -> userRepository.findByIsActive(isActive, pageable)
            else -> userRepository.findAllBy(pageable)
        }.map { it.toDto() }
    }

    @Transactional
    fun createUser(dto: CreateUserDto): UserDto {
        val department = dto.departmentId?.let {
            departmentRepository.findByIdOrNull(it) ?: throw BusinessException(ErrorCode.DEPARTMENT_NOT_FOUND)
        }
        val user = User(
            pinfl = dto.pinfl,
            fullName = dto.fullName ?: dto.pinfl,
            email = dto.email,
            role = dto.role,
            department = department,
            isActive = true,
        )
        return userRepository.save(user).toDto().also {
            log.info("User created by admin: userId={} role={}", it.id, it.role)
        }
    }

    @Transactional
    fun updateUser(id: UUID, dto: UpdateUserDto): UserDto {
        val user = userRepository.findByIdOrNull(id) ?: throw BusinessException(ErrorCode.USER_NOT_FOUND)

        dto.role?.let { user.role = it }
        dto.isActive?.let { user.isActive = it }
        dto.departmentId?.let { deptId ->
            user.department = departmentRepository.findByIdOrNull(deptId)
                ?: throw BusinessException(ErrorCode.DEPARTMENT_NOT_FOUND)
        }

        return userRepository.save(user).toDto().also {
            log.info("User updated by admin: userId={} role={} isActive={}", id, user.role, user.isActive)
        }
    }

    @Transactional
    fun updatePhone(userId: UUID, phone: String): UserDto {
        val user = userRepository.findByIdOrNull(userId) ?: throw BusinessException(ErrorCode.USER_NOT_FOUND)
        user.phoneNumber = phone
        return userRepository.save(user).toDto().also {
            log.info("Phone updated: userId={}", userId)
        }
    }

    @Transactional(readOnly = true)
    fun getModerator(): UserDto? =
        userRepository.findFirstByRoleAndIsActive(Role.MODERATOR, true).map { it.toDto() }.orElse(null)

    // ─── Departments ─────────────────────────────────────────────────────────

    @Transactional(readOnly = true)
    // TODO: Add pagination if department count grows large (currently small and stable)
    fun listDepartments(): List<DepartmentDto> =
        departmentRepository.findAll().map { it.toDepartmentDto() }

    @Transactional
    fun createDepartment(dto: CreateDepartmentDto): DepartmentDto {
        val dept = Department(name = dto.name)
        return departmentRepository.save(dept).toDepartmentDto().also {
            log.info("Department created: id={}", it.id)
        }
    }

    @Transactional
    fun updateDepartment(id: UUID, dto: UpdateDepartmentDto): DepartmentDto {
        val dept = departmentRepository.findByIdOrNull(id) ?: throw BusinessException(ErrorCode.DEPARTMENT_NOT_FOUND)
        dept.name = dto.name
        return departmentRepository.save(dept).toDepartmentDto()
    }
}

