package uz.gov.imvarxiv.request.application

import org.slf4j.LoggerFactory
import org.springframework.data.repository.findByIdOrNull
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import uz.gov.imvarxiv.request.application.dto.CreateTemplateDto
import uz.gov.imvarxiv.request.application.dto.RequestTemplateDto
import uz.gov.imvarxiv.request.application.dto.UpdateTemplateDto
import uz.gov.imvarxiv.request.application.dto.toDto
import uz.gov.imvarxiv.request.domain.RequestTemplate
import uz.gov.imvarxiv.request.infrastructure.RequestTemplateRepository
import uz.gov.imvarxiv.shared.exception.BusinessException
import uz.gov.imvarxiv.shared.exception.ErrorCode
import uz.gov.imvarxiv.shared.security.UserPrincipal
import java.util.UUID

@Service
class RequestTemplateService(
    private val templateRepository: RequestTemplateRepository,
) {
    private val log = LoggerFactory.getLogger(this::class.java)

    @Transactional(readOnly = true)
    fun list(): List<RequestTemplateDto> = templateRepository.findAll().map { it.toDto() }

    @Transactional
    fun create(dto: CreateTemplateDto, principal: UserPrincipal): RequestTemplateDto {
        val template = RequestTemplate(name = dto.name, content = dto.content, createdBy = principal.id)
        return templateRepository.save(template).toDto().also {
            log.info("Template created: id={}", it.id)
        }
    }

    @Transactional
    fun update(id: UUID, dto: UpdateTemplateDto): RequestTemplateDto {
        val template = templateRepository.findByIdOrNull(id)
            ?: throw BusinessException(ErrorCode.TEMPLATE_NOT_FOUND)
        dto.name?.let { template.name = it }
        dto.content?.let { template.content = it }
        return templateRepository.save(template).toDto()
    }

    @Transactional
    fun delete(id: UUID) {
        if (!templateRepository.existsById(id)) throw BusinessException(ErrorCode.TEMPLATE_NOT_FOUND)
        templateRepository.deleteById(id)
    }
}

